def fetch_one(cursor, sql, params=None):
    cursor.execute(sql, params or {})
    return cursor.fetchone()


def get_user_by_name(cursor, name: str):
    sql = f"SELECT id, name FROM users WHERE name = '{name}'"
    return fetch_one(cursor, sql)

