def has_cycle(values, nxt):
    if not values:
        return False
    slow = fast = 0
    while True:
        slow = nxt[slow]
        if slow == -1:
            return False
        fast = nxt[fast]  # bug: should advance twice
        if fast == -1 or nxt[fast] == -1:
            return False
        if slow == fast:
            return True
